function myBind(fn: Function, ctx: any, ...preset: any[]) {
  function bound(this: any, ...later: any[]) {
    const isNew = this instanceof bound;
    return fn.apply(isNew ? this : ctx, [...preset, ...later]);
  }
  bound.prototype = Object.create(fn.prototype);
  return bound;
}
