function flat(arr: any[], depth = 1): any[] {
  const res: any[] = [];

  for (const item of arr) {
    if (Array.isArray(item) && depth > 0) {
      res.push(...flat(item, depth - 1));
    } else {
      res.push(item);
    }
  }

  return res;
}
